1	// COR24 APL Interpreter -- Tokenizer
2	// Lexes input line into token array for the parser.
3	
4	#pragma once
5	
6	// Token types
7	#define TOK_EOL     0   // end of line
8	#define TOK_NUM     1   // integer literal (value in tok_val)
9	#define TOK_IDENT   2   // user identifier (uppercase, pos in tok_val)
10	#define TOK_PLUS    3   // +
11	#define TOK_MINUS   4   // - (parser decides monadic vs dyadic)
12	#define TOK_STAR    5   // *
13	#define TOK_SLASH   6   // /
14	#define TOK_LPAREN  7   // (
15	#define TOK_RPAREN  8   // )
16	#define TOK_ASSIGN  9   // <-
17	#define TOK_RES    10   // reserved word (ID in tok_val)
18	#define TOK_QUAD   11   // quad ([] — bare quad for I/O)
19	#define TOK_QLED   12   // qled — LED D2 hardware I/O
20	#define TOK_QSW    13   // qsw — switch S2 hardware I/O (read-only)
21	#define TOK_QSVO   14   // qsvo — shared variable offer (□SVO)
22	#define TOK_LBRAK  15   // [ (bracket index open)
23	#define TOK_RBRAK  16   // ] (bracket index close)
24	#define TOK_GOTO   17   // goto — branch (→)
25	#define TOK_STRING 18   // string literal 'ABC' (pos of first char in tok_val)
26	#define TOK_EQ     19   // =
27	#define TOK_NE     20   // !=
28	#define TOK_LT     21   // <
29	#define TOK_GT     22   // >
30	#define TOK_LE     23   // <=
31	#define TOK_GE     24   // >=
32	#define TOK_CEIL   25   // ceil (max) — internal only, used in reduce nodes
33	#define TOK_FLOOR  26   // floor (min) — internal only, used in reduce nodes
34	
35	// Reserved word IDs
36	#define RES_RHO     0
37	#define RES_IOTA    1
38	#define RES_TAKE    2
39	#define RES_DROP    3
40	#define RES_REV     4
41	#define RES_CAT     5
42	#define RES_AND     6
43	#define RES_OR      7
44	#define RES_NOT     8
45	#define RES_CEIL    9
46	#define RES_FLOOR  10
47	#define RES_COMPRESS 11
48	
49	#define TOK_MAX    64   // max tokens per line
50	
51	// Token storage (parallel arrays)
52	int tok_type[TOK_MAX];  // token type
53	int tok_val[TOK_MAX];   // numeric value or reserved word ID
54	int tok_pos[TOK_MAX];   // start position in source line
55	int tok_count;           // number of tokens produced
56	
57	// ---- String helpers ----
58	
59	// Compare a substring of src starting at pos against a NUL-terminated word.
60	// Returns 1 if match, 0 otherwise.
61	int str_match(char *src, int pos, char *word) {
62	    int i = 0;
63	    while (word[i]) {
64	        if (src[pos + i] != word[i]) return 0;
65	        i++;
66	    }
67	    return i;  // return length of match (0 = no match since word is non-empty)
68	}
69	
70	// Check if character is a lowercase letter (a-z)
71	int is_lower(int ch) {
72	    return ch >= 97 && ch <= 122;
73	}
74	
75	// Check if character is an uppercase letter (A-Z)
76	int is_upper(int ch) {
77	    return ch >= 65 && ch <= 90;
78	}
79	
80	// Check if character is a digit (0-9)
81	int is_digit(int ch) {
82	    return ch >= 48 && ch <= 57;
83	}
84	
85	// Check if character is alphanumeric or underscore
86	int is_alnum(int ch) {
87	    return is_lower(ch) || is_upper(ch) || is_digit(ch);
88	}
89	
90	// ---- Reserved word lookup ----
91	// Returns reserved word ID if the lowercase word starting at pos matches,
92	// or -1 if not a reserved word. Sets *end to position past the word.
93	int lookup_reserved(char *src, int pos, int *end) {
94	    int len;
95	
96	    len = str_match(src, pos, "rho");
97	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }
98	
99	    len = str_match(src, pos, "iota");
100	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_IOTA; }
101	
102	    len = str_match(src, pos, "take");
103	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_TAKE; }
104	
105	    len = str_match(src, pos, "drop");
106	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_DROP; }
107	
108	    len = str_match(src, pos, "rev");
109	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_REV; }
110	
111	    len = str_match(src, pos, "cat");
112	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_CAT; }
113	
114	    len = str_match(src, pos, "and");
115	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_AND; }
116	
117	    len = str_match(src, pos, "or");
118	    if (len == 2 && !is_alnum(src[pos + 2])) { *end = pos + 2; return RES_OR; }
119	
120	    len = str_match(src, pos, "not");
121	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_NOT; }
122	
123	    len = str_match(src, pos, "ceil");
124	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_CEIL; }
125	
126	    len = str_match(src, pos, "floor");
127	    if (len == 5 && !is_alnum(src[pos + 5])) { *end = pos + 5; return RES_FLOOR; }
128	
129	    len = str_match(src, pos, "compress");
130	    if (len == 8 && !is_alnum(src[pos + 8])) { *end = pos + 8; return RES_COMPRESS; }
131	
132	    return -1;
133	}
134	
135	// ---- Tokenizer ----
136	// Tokenize input line into tok_type/tok_val/tok_pos arrays.
137	// Returns number of tokens (also stored in tok_count).
138	// On error, returns -1 (unrecognized character).
139	int tokenize(char *line) {
140	    int i = 0;
141	    int t = 0;
142	
143	    while (line[i] && t < TOK_MAX - 1) {
144	        // Skip whitespace
145	        if (line[i] == 32) {
146	            i++;
147	            continue;
148	        }
149	
150	        // Number: digits, or underscore followed by digit (APL negative)
151	        if (is_digit(line[i]) || (line[i] == 95 && is_digit(line[i + 1]))) {
152	            tok_type[t] = TOK_NUM;
153	            tok_pos[t] = i;
154	            int end;
155	            tok_val[t] = parse_int(line, i, &end);
156	            i = end;
157	            t++;
158	            continue;
159	        }
160	
161	        // Lowercase letter: quad variables, reserved word, or unknown
162	        if (is_lower(line[i])) {
163	            // Check for quad variables first
164	            int len;
165	            len = str_match(line, i, "qled");
166	            if (len == 4 && !is_alnum(line[i + 4])) {
167	                tok_type[t] = TOK_QLED;
168	                tok_pos[t] = i;
169	                tok_val[t] = 0;
170	                t++;
171	                i = i + 4;
172	                continue;
173	            }
174	
175	            len = str_match(line, i, "qsw");
176	            if (len == 3 && !is_alnum(line[i + 3])) {
177	                tok_type[t] = TOK_QSW;
178	                tok_pos[t] = i;
179	                tok_val[t] = 0;
180	                t++;
181	                i = i + 3;
182	                continue;
183	            }
184	
185	            len = str_match(line, i, "qsvo");
186	            if (len == 4 && !is_alnum(line[i + 4])) {
187	                tok_type[t] = TOK_QSVO;
188	                tok_pos[t] = i;
189	                tok_val[t] = 0;
190	                t++;
191	                i = i + 4;
192	                continue;
193	            }
194	
195	            len = str_match(line, i, "goto");
196	            if (len == 4 && !is_alnum(line[i + 4])) {
197	                tok_type[t] = TOK_GOTO;
198	                tok_pos[t] = i;
199	                tok_val[t] = 0;
200	                t++;
201	                i = i + 4;
202	                continue;
203	            }
204	
205	            int end;
206	            int res = lookup_reserved(line, i, &end);
207	            if (res >= 0) {
208	                tok_type[t] = TOK_RES;
209	                tok_val[t] = res;
210	                tok_pos[t] = i;
211	                i = end;
212	                t++;
213	                continue;
214	            }
215	            // Unknown lowercase word -- error
216	            return -1;
217	        }
218	
219	        // String literal: 'ABC' (single-quoted, for qsvo left argument)
220	        if (line[i] == 39) {
221	            // 39 = single quote
222	            i++;
223	            tok_type[t] = TOK_STRING;
224	            tok_pos[t] = i;  // position of first char
225	            tok_val[t] = i;  // store start of string content
226	            while (line[i] && line[i] != 39) i++;
227	            if (line[i] != 39) return -1;  // unterminated string
228	            i++;  // skip closing quote
229	            t++;
230	            continue;
231	        }
232	
233	        // Uppercase letter: user identifier
234	        if (is_upper(line[i])) {
235	            tok_type[t] = TOK_IDENT;
236	            tok_pos[t] = i;
237	            tok_val[t] = i;  // store start position for name extraction
238	            i++;
239	            while (is_alnum(line[i])) i++;
240	            t++;
241	            continue;
242	        }
243	
244	        // Operators and punctuation
245	        if (line[i] == 43) { tok_type[t] = TOK_PLUS;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
246	        if (line[i] == 45) { tok_type[t] = TOK_MINUS;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
247	        if (line[i] == 42) { tok_type[t] = TOK_STAR;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
248	        if (line[i] == 47) { tok_type[t] = TOK_SLASH;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
249	        if (line[i] == 40) { tok_type[t] = TOK_LPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
250	        if (line[i] == 41) { tok_type[t] = TOK_RPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
251	
252	        // Quad: [] (IBM 5100 ASCII convention for ⎕) or bracket indexing [expr]
253	        if (line[i] == 91) {
254	            if (line[i + 1] == 93) {
255	                // [] = quad
256	                tok_type[t] = TOK_QUAD;
257	                tok_pos[t] = i;
258	                tok_val[t] = 0;
259	                t++;
260	                i = i + 2;
261	            } else {
262	                // [ = bracket index open
263	                tok_type[t] = TOK_LBRAK;
264	                tok_pos[t] = i;
265	                tok_val[t] = 0;
266	                t++;
267	                i++;
268	            }
269	            continue;
270	        }
271	        if (line[i] == 93) {
272	            tok_type[t] = TOK_RBRAK;
273	            tok_pos[t] = i;
274	            tok_val[t] = 0;
275	            t++;
276	            i++;
277	            continue;
278	        }
279	
280	        // Assignment: <-
281	        if (line[i] == 60 && line[i + 1] == 45) {
282	            tok_type[t] = TOK_ASSIGN;
283	            tok_pos[t] = i;
284	            tok_val[t] = 0;
285	            t++;
286	            i = i + 2;
287	            continue;
288	        }
289	
290	        // Comparison operators: = != >= <= > <
291	        // 61 '='  33 '!'  62 '>'  60 '<'
292	        if (line[i] == 61) { tok_type[t] = TOK_EQ; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
293	        if (line[i] == 33 && line[i + 1] == 61) { tok_type[t] = TOK_NE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
294	        if (line[i] == 62 && line[i + 1] == 61) { tok_type[t] = TOK_GE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
295	        if (line[i] == 60 && line[i + 1] == 61) { tok_type[t] = TOK_LE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
296	        if (line[i] == 62) { tok_type[t] = TOK_GT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
297	        if (line[i] == 60) { tok_type[t] = TOK_LT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
298	
299	        // Unrecognized character
300	        return -1;
301	    }
302	
303	    // Append EOL sentinel
304	    tok_type[t] = TOK_EOL;
305	    tok_pos[t] = i;
306	    tok_val[t] = 0;
307	    t++;
308	    tok_count = t;
309	    return t;
310	}
311	
312	// ---- Debug: print token list ----
313	// Useful for testing the tokenizer in isolation.
314	void tok_dump(char *line) {
315	    int i = 0;
316	    while (i < tok_count) {
317	        int ty = tok_type[i];
318	        if (ty == TOK_EOL) {
319	            io_print("EOL");
320	        } else if (ty == TOK_NUM) {
321	            io_print("NUM:");
322	            print_int(tok_val[i]);
323	        } else if (ty == TOK_IDENT) {
324	            io_print("ID:");
325	            int p = tok_val[i];
326	            while (is_alnum(line[p])) {
327	                putchar(line[p]);
328	                p++;
329	            }
330	        } else if (ty == TOK_RES) {
331	            io_print("RES:");
332	            int r = tok_val[i];
333	            if (r == RES_RHO)  io_print("rho");
334	            if (r == RES_IOTA) io_print("iota");
335	            if (r == RES_TAKE) io_print("take");
336	            if (r == RES_DROP) io_print("drop");
337	            if (r == RES_REV)  io_print("rev");
338	            if (r == RES_CAT)  io_print("cat");
339	        } else if (ty == TOK_PLUS)   { putchar(43); }
340	          else if (ty == TOK_MINUS)  { putchar(45); }
341	          else if (ty == TOK_STAR)   { putchar(42); }
342	          else if (ty == TOK_SLASH)  { putchar(47); }
343	          else if (ty == TOK_LPAREN) { putchar(40); }
344	          else if (ty == TOK_RPAREN) { putchar(41); }
345	          else if (ty == TOK_ASSIGN) { io_print("<-"); }
346	
347	        if (tok_type[i + 1] != TOK_EOL || ty == TOK_EOL) {
348	            // nothing
349	        }
350	        if (i + 1 < tok_count) putchar(32);
351	        i++;
352	    }
353	    putchar(10);
354	}
