1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	#define NODE_QLED  10   // qled read (no children)
21	#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
22	#define NODE_QSW   12   // qsw read (no children, read-only)
23	#define NODE_QSVO  13   // shared variable offer (val = sym index, right = AP expr)
24	#define NODE_SVO_READ  14   // shared var indexed read (val = sym index, right = index expr)
25	#define NODE_SVO_WRITE 15  // shared var indexed write (val = sym index, left = index, right = value)
26	#define NODE_GOTO  16   // unconditional branch (right = target expr)
27	#define NODE_CGOTO 17   // conditional branch (left = cond, right = target)
28	#define NODE_FNCALL 18  // user function call (val = fn index, left = left arg/-1, right = right arg)
29	
30	#define AST_MAX 64
31	
32	// AST storage (parallel arrays)
33	int node_type[AST_MAX];
34	int node_val[AST_MAX];
35	int node_left[AST_MAX];
36	int node_right[AST_MAX];
37	int node_count;
38	
39	// Parser state
40	int parse_pos;
41	int parse_err;
42	char *parse_line;   // source line for identifier lookup
43	
44	// Allocate a new AST node
45	int ast_new() {
46	    if (node_count >= AST_MAX) {
47	        parse_err = 1;
48	        return 0;
49	    }
50	    int n = node_count;
51	    node_count++;
52	    node_left[n] = -1;
53	    node_right[n] = -1;
54	    return n;
55	}
56	
57	int ast_num(int val) {
58	    int n = ast_new();
59	    node_type[n] = NODE_NUM;
60	    node_val[n] = val;
61	    return n;
62	}
63	
64	int ast_binop(int op, int left, int right) {
65	    int n = ast_new();
66	    node_type[n] = NODE_BINOP;
67	    node_val[n] = op;
68	    node_left[n] = left;
69	    node_right[n] = right;
70	    return n;
71	}
72	
73	int ast_neg(int operand) {
74	    int n = ast_new();
75	    node_type[n] = NODE_NEG;
76	    node_right[n] = operand;
77	    return n;
78	}
79	
80	int ast_ident(int sym_idx) {
81	    int n = ast_new();
82	    node_type[n] = NODE_IDENT;
83	    node_val[n] = sym_idx;
84	    return n;
85	}
86	
87	int ast_assign(int sym_idx, int expr) {
88	    int n = ast_new();
89	    node_type[n] = NODE_ASSIGN;
90	    node_val[n] = sym_idx;
91	    node_right[n] = expr;
92	    return n;
93	}
94	
95	int ast_vec(int heap_idx) {
96	    int n = ast_new();
97	    node_type[n] = NODE_VEC;
98	    node_val[n] = heap_idx;
99	    return n;
100	}
101	
102	int ast_monad(int res_id, int operand) {
103	    int n = ast_new();
104	    node_type[n] = NODE_MONAD;
105	    node_val[n] = res_id;
106	    node_right[n] = operand;
107	    return n;
108	}
109	
110	int ast_dyad(int res_id, int left, int right) {
111	    int n = ast_new();
112	    node_type[n] = NODE_DYAD;
113	    node_val[n] = res_id;
114	    node_left[n] = left;
115	    node_right[n] = right;
116	    return n;
117	}
118	
119	int ast_reduce(int op, int operand) {
120	    int n = ast_new();
121	    node_type[n] = NODE_REDUCE;
122	    node_val[n] = op;
123	    node_right[n] = operand;
124	    return n;
125	}
126	
127	// Check if a reserved word can be used dyadically
128	int is_dyadic_res(int res_id) {
129	    return res_id == RES_RHO || res_id == RES_TAKE || res_id == RES_DROP || res_id == RES_CAT || res_id == RES_AND || res_id == RES_OR || res_id == RES_CEIL || res_id == RES_FLOOR || res_id == RES_COMPRESS;
130	}
131	
132	// Temporary buffer for collecting strand elements
133	int strand_buf[64];
134	
135	int is_binop(int ty) {
136	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH ||
137	           ty == TOK_EQ || ty == TOK_NE || ty == TOK_LT || ty == TOK_GT ||
138	           ty == TOK_LE || ty == TOK_GE;
139	}
140	
141	// Check if token at pos could start an expression (for function call detection)
142	int can_start_expr(int pos) {
143	    int ty = tok_type[pos];
144	    if (ty == TOK_NUM || ty == TOK_LPAREN || ty == TOK_IDENT ||
145	        ty == TOK_MINUS || ty == TOK_RES || ty == TOK_QLED || ty == TOK_QSW) return 1;
146	    if (is_binop(ty) && tok_type[pos + 1] == TOK_SLASH) return 1;  // reduce
147	    return 0;
148	}
149	
150	// Combined parse function avoids mutual recursion.
151	// mode 0 = expression, mode 1 = value only
152	int parse_node(int mode);
153	
154	int parse_node(int mode) {
155	    if (parse_err) return 0;
156	
157	    int left;
158	    int ty = tok_type[parse_pos];
159	
160	    // -- Parse a value --
161	
162	    if (ty == TOK_NUM) {
163	        left = ast_num(tok_val[parse_pos]);
164	        parse_pos++;
165	
166	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
167	        if (tok_type[parse_pos] == TOK_NUM) {
168	            strand_buf[0] = node_val[left];
169	            int count = 1;
170	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
171	                strand_buf[count] = tok_val[parse_pos];
172	                parse_pos++;
173	                count++;
174	            }
175	            int aidx = arr_vector(count);
176	            if (aidx < 0) { parse_err = 1; return 0; }
177	            int si = 0;
178	            while (si < count) {
179	                arr_set(aidx, si, strand_buf[si]);
180	                si++;
181	            }
182	            left = ast_vec(aidx);
183	        }
184	    } else if (ty == TOK_LPAREN) {
185	        parse_pos++;
186	        left = parse_node(0);
187	        if (parse_err) return 0;
188	        if (tok_type[parse_pos] != TOK_RPAREN) {
189	            parse_err = 1;
190	            return 0;
191	        }
192	        parse_pos++;
193	    } else if (ty == TOK_QLED) {
194	        int n = ast_new();
195	        node_type[n] = NODE_QLED;
196	        left = n;
197	        parse_pos++;
198	    } else if (ty == TOK_QSW) {
199	        int n = ast_new();
200	        node_type[n] = NODE_QSW;
201	        left = n;
202	        parse_pos++;
203	    } else if (ty == TOK_STRING) {
204	        // String literal becomes an identifier (for 'NAME' qsvo AP)
205	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
206	        if (sym_idx < 0) { parse_err = 1; return 0; }
207	        left = ast_ident(sym_idx);
208	        parse_pos++;
209	    } else if (ty == TOK_IDENT) {
210	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
211	        if (sym_idx < 0) { parse_err = 1; return 0; }
212	        parse_pos++;
213	        // Check for monadic function call
214	        int fi = fn_lookup(sym_idx);
215	        if (fi >= 0 && fn_left_sym[fi] < 0 && can_start_expr(parse_pos)) {
216	            // Monadic user function call: FN expr
217	            int arg = parse_node(0);
218	            if (parse_err) return 0;
219	            int nd = ast_new();
220	            node_type[nd] = NODE_FNCALL;
221	            node_val[nd] = fi;
222	            node_right[nd] = arg;
223	            left = nd;
224	        } else if (tok_type[parse_pos] == TOK_LBRAK) {
225	            // IDENT[expr] -- shared variable indexed read
226	            parse_pos++;
227	            int idx_expr = parse_node(0);
228	            if (parse_err) return 0;
229	            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
230	            parse_pos++;
231	            int nd = ast_new();
232	            node_type[nd] = NODE_SVO_READ;
233	            node_val[nd] = sym_idx;
234	            node_right[nd] = idx_expr;
235	            left = nd;
236	        } else {
237	            left = ast_ident(sym_idx);
238	        }
239	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
240	        // Reduce operator: +/ -/ */ (op followed by slash)
241	        int op = ty;
242	        parse_pos = parse_pos + 2;
243	        int operand = parse_node(0);
244	        if (parse_err) return 0;
245	        left = ast_reduce(op, operand);
246	    } else if (ty == TOK_RES && (tok_val[parse_pos] == RES_CEIL || tok_val[parse_pos] == RES_FLOOR) && tok_type[parse_pos + 1] == TOK_SLASH) {
247	        // Reduce with ceil/ or floor/ (max-reduce, min-reduce)
248	        int op = (tok_val[parse_pos] == RES_CEIL) ? TOK_CEIL : TOK_FLOOR;
249	        parse_pos = parse_pos + 2;
250	        int operand = parse_node(0);
251	        if (parse_err) return 0;
252	        left = ast_reduce(op, operand);
253	    } else if (ty == TOK_RES) {
254	        // Monadic primitive function (e.g. iota expr)
255	        int res_id = tok_val[parse_pos];
256	        parse_pos++;
257	        int operand = parse_node(0);
258	        if (parse_err) return 0;
259	        left = ast_monad(res_id, operand);
260	    } else if (ty == TOK_MINUS) {
261	        // Monadic negate: applies to entire right expression (APL rule)
262	        parse_pos++;
263	        int operand = parse_node(0);
264	        if (parse_err) return 0;
265	        left = ast_neg(operand);
266	    } else {
267	        parse_err = 1;
268	        return 0;
269	    }
270	
271	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
272	
273	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
274	        int op = tok_type[parse_pos];
275	        parse_pos++;
276	        int right = parse_node(0);
277	        if (parse_err) return 0;
278	        return ast_binop(op, left, right);
279	    }
280	
281	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
282	        int res_id = tok_val[parse_pos];
283	        parse_pos++;
284	        int right = parse_node(0);
285	        if (parse_err) return 0;
286	        return ast_dyad(res_id, left, right);
287	    }
288	
289	    // Shared variable offer: 'NAME' qsvo EXPR  (or legacy: IDENT qsvo EXPR)
290	    if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
291	        int sym_idx = node_val[left];
292	        parse_pos++;
293	        int right = parse_node(0);
294	        if (parse_err) return 0;
295	        int n = ast_new();
296	        node_type[n] = NODE_QSVO;
297	        node_val[n] = sym_idx;
298	        node_right[n] = right;
299	        return n;
300	    }
301	
302	    // Dyadic user function call: expr FN expr
303	    if (mode == 0 && tok_type[parse_pos] == TOK_IDENT) {
304	        int dsym = sym_lookup(parse_line, tok_val[parse_pos]);
305	        if (dsym >= 0) {
306	            int dfi = fn_lookup(dsym);
307	            if (dfi >= 0 && fn_left_sym[dfi] >= 0) {
308	                parse_pos++;
309	                int right = parse_node(0);
310	                if (parse_err) return 0;
311	                int nd = ast_new();
312	                node_type[nd] = NODE_FNCALL;
313	                node_val[nd] = dfi;
314	                node_left[nd] = left;
315	                node_right[nd] = right;
316	                return nd;
317	            }
318	        }
319	    }
320	
321	    return left;
322	}
