        char *fexec = fline;
        if (is_upper(fline[0])) {
            int fj = 1;
            while (is_alnum(fline[fj])) fj++;
            if (fline[fj] == 58) {  // ':'
                fj++;
                while (fline[fj] == 32) fj++;
                fexec = fline + fj;
                if (fexec[0] == 0) { fpc++; continue; }
            }
        }

