        if (ntok < 0) { eval_err = 1; fdone = 1; continue; }

        int froot = parse(fexec);
        if (froot < 0) { eval_err = 1; fdone = 1; continue; }

        eval_err = 0;
        branch_target = -1;
        int fres = eval(froot);

        if (eval_err) { fdone = 1; continue; }

