1	// COR24 APL Interpreter -- main entry point
2	// Phase 9: batch mode support via APL image loading
3	
4	#include <stdio.h>
5	#include "io.h"
6	#include "num.h"
7	#include "arr.h"
8	#include "tok.h"
9	#include "sym.h"
10	#include "fn.h"
11	#include "parse.h"
12	#include "eval.h"
13	
14	// APL image format constants
15	// Image pointer at 0x09FF00: if non-zero, points to APL image in SRAM
16	// Image data loaded at 0x080000 via --load-binary
17	// Format: newline-separated APL lines, null-terminated
18	#define APL_IMAGE_PTR  0x09FF00
19	#define APL_IMAGE_BASE 0x080000
20	
21	// Batch mode state
22	int batch_mode;      // 1 = reading from SRAM image, 0 = interactive UART
23	char *batch_ptr;     // current read position in APL image
24	
25	// Read next line from APL image in SRAM.
26	// Copies up to len-1 chars into buf, null-terminates.
27	// Returns number of chars read (0 on empty line, -1 on end of image).
28	int batch_getline(char *buf, int len) {
29	    if (*batch_ptr == 0) return -1;  // end of image
30	    int pos = 0;
31	    int maxpos = len - 1;
32	    while (*batch_ptr && *batch_ptr != 10 && pos < maxpos) {
33	        buf[pos] = *batch_ptr;
34	        pos++;
35	        batch_ptr++;
36	    }
37	    buf[pos] = 0;
38	    if (*batch_ptr == 10) batch_ptr++;  // skip newline
39	    return pos;
40	}
41	
42	// Program line buffer for multi-line programs
43	// 64 lines * 120 chars = 7680 bytes
44	#define PROG_MAX 64
45	#define PROG_LINE 120
46	
47	char prog_buf[7680];
48	int prog_count;  // highest line number stored (1-based count)
49	
50	void prog_store(char *src, int idx) {
51	    char *dst = prog_buf + idx * PROG_LINE;
52	    int k = 0;
53	    while (src[k] && k < PROG_LINE - 1) {
54	        dst[k] = src[k];
55	        k++;
56	    }
57	    dst[k] = 0;
58	}
59	
60	// Get pointer to program line (0-based index)
61	char *prog_get(int idx) {
62	    return prog_buf + idx * PROG_LINE;
63	}
64	
65	// Clear all program lines
66	void prog_clear() {
67	    int i = 0;
68	    while (i < PROG_MAX) {
69	        prog_buf[i * PROG_LINE] = 0;
70	        i++;
71	    }
72	    prog_count = 0;
73	}
74	
75	// Pre-scan labels in stored program before execution
76	void prog_scan_labels() {
77	    int i = 0;
78	    while (i < prog_count) {
79	        char *ln = prog_get(i);
80	        if (is_upper(ln[0])) {
81	            int j = 1;
82	            while (is_alnum(ln[j])) j++;
83	            if (ln[j] == 58) {  // ':'
84	                int sym_idx = sym_lookup(ln, 0);
85	                if (sym_idx >= 0) {
86	                    sym_val[sym_idx] = arr_scalar(i + 1);  // 1-based line number
87	                    sym_set_flag[sym_idx] = 1;
88	                }
89	            }
90	        }
91	        i++;
92	    }
93	}
94	
95	// Check if line starts with [N] line entry syntax
96	// Returns line number (1-based) if so, 0 if not
97	// Sets *rest to point past the "] " to the line content
98	int prog_parse_entry(char *line, char **rest) {
99	    if (line[0] != 91) return 0;  // '['
100	    int i = 1;
101	    if (!is_digit(line[i])) return 0;
102	    int num = 0;
103	    while (is_digit(line[i])) {
104	        num = num * 10 + (line[i] - 48);
105	        i++;
106	    }
107	    if (line[i] != 93) return 0;  // ']'
108	    i++;
109	    while (line[i] == 32) i++;  // skip spaces
110	    *rest = line + i;
111	    return num;
112	}
